// Extract clean text from website HTML and merge with firm data
const firm = $('Loop Over Qualified Firms1').first().json;
const scrapeResp = $input.first();

let rawHtml = '';
try {
  rawHtml = scrapeResp.json.data || scrapeResp.json.body || scrapeResp.json || '';
  if (typeof rawHtml !== 'string') rawHtml = JSON.stringify(rawHtml);
} catch(e) { rawHtml = ''; }

// Strip HTML tags, get clean text
const cleanText = rawHtml
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 3000);

// Detect centralized/network phrases
const lower = cleanText.toLowerCase();
const centralizedPhrases = ['operating partner','value creation','portfolio operations',
  'capstone','in-house','dedicated team','full-time','embedded'].filter(p => lower.includes(p));
const networkPhrases = ['advisor network','external advisor','venture partner',
  'operating executive','industrial advisor','executive in residence',
  'network of advisors'].filter(p => lower.includes(p));

// Detect team page and portfolio page URLs
let teamPageUrl = firm.team_page_url || '';
let portfolioPageUrl = firm.portfolio_page_url || '';

// Try to find team/portfolio links in HTML
const teamMatch = rawHtml.match(/href=["']([^"']*(?:team|people|professionals|leadership)[^"']*)["']/i);
if (teamMatch && !teamPageUrl) teamPageUrl = teamMatch[1];

const portfolioMatch = rawHtml.match(/href=["']([^"']*(?:portfolio|investments|companies)[^"']*)["']/i);
if (portfolioMatch && !portfolioPageUrl) portfolioPageUrl = portfolioMatch[1];

return [{ json: {
  ...firm,
  text_sample_for_ai: cleanText || firm.text_sample_for_ai || '',
  centralized_phrases: centralizedPhrases.join(', ') || firm.centralized_phrases || '',
  network_phrases: networkPhrases.join(', ') || firm.network_phrases || '',
  team_page_url: teamPageUrl,
  portfolio_page_url: portfolioPageUrl,
  scrape_quality: cleanText.length > 500 ? 'good' : cleanText.length > 100 ? 'partial' : 'failed'
}}];

