const firm = $('Loop Over Qualified Firms1').first().json;
const aiResp = $('Classification AI1').first().json;
let raw = aiResp.output || aiResp.text || '';
let p2 = {};
try {
  const m = raw.match(/\{[\s\S]*\}/);
  if (!m) throw new Error('no JSON');
  p2 = JSON.parse(m[0]);
} catch(e) {
  p2 = { classification:'unclear', classification_confidence:0,
    classification_evidence:'AI parse error', check1_team_page:'',
    check2_language:'', check3_linkedin:'', check5_annual_report:'',
    check6_board_composition:'', check7_umbrex:'', operating_team_name:null,
    targeting_paths:['Manual Review'], flag_for_manual_review:true };
}

// UNCLEAR + confirmed PE firm → default to DECENTRALIZED
const cls = (p2.classification || '').toLowerCase();
const conf = p2.classification_confidence || 0;
if (cls === 'unclear' && conf < 60) {
  const ind = (firm.industry || '').toLowerCase();
  const kw  = (firm.keywords || '').toLowerCase();
  const isPE = ind.includes('private equity') || ind.includes('venture') ||
               kw.includes('private equity') || kw.includes('buyout') ||
               kw.includes('venture capital');
  if (isPE) {
    p2.classification = 'decentralized';
    p2.classification_confidence = 40;
    p2.classification_evidence = (p2.classification_evidence || '') +
      ' | No ops team signals found in website + 3 web searches — defaulted to Decentralized (confirmed PE firm with no visible operating model).';
    p2.targeting_paths = ['Path B','Path D'];
    p2.flag_for_manual_review = false;
  }
}

let status = firm.status || 'Qualified';
if (p2.flag_for_manual_review || (p2.classification_confidence || 0) < 50)
  status = 'Qualified — Manual Review (Classification)';

return [{ json: {
  pe_firm_name:              firm.pe_firm_name,
  website_url:               firm.website_url,
  company_linkedin_url:      firm.company_linkedin_url,
  company_country:           firm.company_country,
  industry:                  firm.industry,
  headcount:                 firm.headcount,
  aum_in_billions:           firm.aum_in_billions,
  scrape_quality:            firm.scrape_quality,
  run_date:                  firm.run_date,
  status:                    status,
  gate1_apac_mandate:        firm.gate1_apac_mandate,
  gate1_evidence:            firm.gate1_evidence,
  gate2_physical_ops:        firm.gate2_physical_ops,
  gate2_evidence:            firm.gate2_evidence,
  gate3_right_size:          firm.gate3_right_size,
  gate3_evidence:            firm.gate3_evidence,
  gate4_apac_deal_flow:      firm.gate4_apac_deal_flow,
  gate4_evidence:            firm.gate4_evidence,
  strong_fit:                firm.strong_fit,
  phase1_confidence:         firm.phase1_confidence,
  classification:            p2.classification            || 'unclear',
  classification_confidence: p2.classification_confidence || 0,
  classification_evidence:   p2.classification_evidence   || '',
  check1_team_page:          p2.check1_team_page          || '',
  check2_language:           p2.check2_language           || '',
  check3_linkedin:           p2.check3_linkedin           || '',
  check5_annual_report:      p2.check5_annual_report      || '',
  check6_board_composition:  p2.check6_board_composition  || '',
  check7_umbrex:             p2.check7_umbrex             || '',
  operating_team_name:       p2.operating_team_name       || null,
  targeting_paths:           JSON.stringify(p2.targeting_paths || []),
  flag_for_manual_review:    p2.flag_for_manual_review    || false,
  team_page_url:             firm.team_page_url,
  portfolio_page_url:        firm.portfolio_page_url,
  text_sample_for_ai:        firm.text_sample_for_ai,
  centralized_phrases:       firm.centralized_phrases,
  network_phrases:           firm.network_phrases,
  active_paths:              JSON.stringify(p2.targeting_paths || []),
  targeting_paths:           JSON.stringify(p2.targeting_paths || []),
  apac_offices_detected:     firm.apac_offices_detected || [],
  sectors_detected:          firm.sectors_detected || '',
  w2_status:                 'done'
}}];
